import fs from "fs";
import path from "path";
import formidable from "formidable";

export const config = {
  api: {
    bodyParser: false, // Required for formidable
  },
};

export default async function handler(req, res) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method Not Allowed" });
  }

  const form = new formidable.IncomingForm();
  form.uploadDir = "./public/uploads";
  form.keepExtensions = true;

  form.parse(req, async (err, fields, files) => {
    if (err) {
      return res.status(500).json({ error: "File upload error" });
    }

    const filePath = files.file[0].filepath;
    const base64File = fs.readFileSync(filePath, { encoding: "base64" });

    // 🔹 Send file to OCR.space API
    const ocrResponse = await fetch("https://api.ocr.space/parse/image", {
      method: "POST",
      headers: {
        apikey: "YOUR_OCR_SPACE_API_KEY",
        "Content-Type": "application/x-www-form-urlencoded",
      },
      body: new URLSearchParams({
        base64image: `data:application/pdf;base64,${base64File}`,
        isOverlayRequired: "true",
        language: "eng",
      }),
    });

    const result = await ocrResponse.json();
    const extractedText = result?.ParsedResults?.[0]?.ParsedText || "";

    // Check if the text contains "marksheet-like" data
    const isMarksheet = /subject|marks|percentage|grade|total/i.test(
      extractedText
    );

    res.status(200).json({ text: extractedText, isMarksheet });
  });
}
